package com.example.demo;

import org.springframework.stereotype.Repository;
import java.util.ArrayList;
import java.util.List;

@Repository
public class CommentRepository {
    private final List<Comment> comments = new ArrayList<>();

    public CommentRepository() {
        // Simulate some comments, some with basic HTML
        comments.add(new Comment(1L, "Alice", "This is the first comment."));
        comments.add(new Comment(2L, "Bob", "Hello <b>world</b> from Bob!"));
        comments.add(new Comment(3L, "Charlie", "A comment with a <i>link</i>: <a href='https://example.com'>Example</a>"));
        comments.add(new Comment(4L, "Diana", "Another comment. <p>New paragraph here.</p>"));
        comments.add(new Comment(5L, "Eve", "This comment has <u>underline</u> and <strong>strong</strong> text."));
    }

    public List<Comment> findAll() {
        return new ArrayList<>(comments); // Return a copy to prevent external modification
    }
}
